  { id: 'libra', name: 'Libra', title: 'The Final Balance', pantheon: 'Zodiac', align: 'Lawful neutral', hp: 210, AC: 0, MR: 60, divineRank: 'Lesser God', category: 'lesser-gods', domain: 'justice, balance, law', symbol: 'scale, sword, star', personality: 'Libra does not decide what is right. She decides what is equal. There is a difference, though mortals rarely survive long enough to explain it. Every choice in her presence becomes weight on a scale that remembers everything ever done, even things not yet committed.', abilities: ['Absolute Balance Field (equalizes all advantages and disadvantages)', 'Judgment Equilibrium (nullifies bias in conflict outcomes)', 'Karmic Reflection (returns harm proportionally across time)', 'Law of Parity (forces systemic equilibrium states)'], str: '18', dex: '18', con: '18', int: '20', wis: '20', cha: '18' },
  { id: 'scorpio', name: 'Scorpio', title: 'The Hidden Hand', pantheon: 'Zodiac', align: 'Neutral evil', hp: 230, AC: -1, MR: 60, divineRank: 'Lesser God', category: 'lesser-gods', domain: 'death, rebirth, secrecy', symbol: 'scorpion, shadow, dagger', personality: 'Scorpio is the god you thank after something terrible has changed you for the better. No one agrees on whether he is cruel or kind, and he does not clarify. He simply ensures that nothing remains what it was, and calls it growth.', abilities: ['Venom of Rebirth (death-transformation cycle control)', 'Shadow Manipulation (environmental concealment shaping)', 'Silent Dominion (undetected divine influence)', 'Death Cycle Reset (controlled resurrection alteration)'], str: '20', dex: '20', con: '20', int: '18', wis: '18', cha: '16' },
  { id: 'sagittarius', name: 'Sagittarius', title: 'The Infinite Arrow', pantheon: 'Zodiac', align: 'Chaotic good', hp: 200, AC: 0, MR: 50, divineRank: 'Lesser God', category: 'lesser-gods', domain: 'freedom, exploration, fate', symbol: 'bow, arrow, horse', personality: 'Sagittarius is always already leaving. Even when she is standing still, she is elsewhere in thought. Stories say she once shot an arrow so far that it has not yet arrived anywhere, and she is still following it out of curiosity rather than obligation.', abilities: ['Infinite Shot (fate-bound trajectory attack)', 'Fate Trajectory Sight (future path prediction)', 'Freedom Break (removes binding constraints)', 'Long Horizon Step (distance compression movement)'], str: '18', dex: '22', con: '16', int: '18', wis: '20', cha: '16' },
  { id: 'capricorn', name: 'Capricorn', title: 'The Eternal Ascent', pantheon: 'Zodiac', align: 'Lawful neutral', hp: 260, AC: 2, MR: 60, divineRank: 'Lesser God', category: 'lesser-gods', domain: 'ambition, endurance, mountains', symbol: 'goat, mountain, spiral', personality: 'Capricorn is what ambition looks like when it has forgotten where the top is. He climbs because stopping would imply there is a ground worth returning to. Even gods feel small near him, as if height itself has become moral.', abilities: ['Ascension Aura (progressive scaling of power)', 'Stone Body Adaptation (environmental resistance)', 'Endless Climb (ignores physical limitation)', 'Pressure Immunity (thrives under overwhelming stress)'], str: '22', dex: '16', con: '22', int: '18', wis: '18', cha: '16' },
  { id: 'aquarius', name: 'Aquarius', title: 'The Thought Stream', pantheon: 'Zodiac', align: 'Neutral good', hp: 190, AC: 0, MR: 55, divineRank: 'Lesser God', category: 'lesser-gods', domain: 'knowledge, water, innovation', symbol: 'water bearer, waves, light', personality: 'Aquarius does not speak in sentences so much as in possibilities. When she looks at a problem, the problem begins to behave differently, as if embarrassed to remain unsolved. Some call her a goddess of invention, others call her a quiet form of revolution.', abilities: ['Idea Manifestation (concept-to-reality conversion)', 'Flow Disruption (breaks systemic coordination)', 'Memory Rewrite (localized perception alteration)', 'Fluid Form Defense (adaptive damage mitigation)'], str: '16', dex: '18', con: '18', int: '22', wis: '20', cha: '18' },
  { id: 'pisces', name: 'Pisces', title: 'The Dreaming Depths', pantheon: 'Zodiac', align: 'Chaotic neutral', hp: 180, AC: 0, MR: 60, divineRank: 'Lesser God', category: 'lesser-gods', domain: 'dreams, illusion, empathy', symbol: 'fish, water, dream', personality: 'Pisces exists in the place where memory stops being reliable. She does not lie; she simply remembers all possibilities at once. Those who stand near her begin to doubt which version of themselves is the original, and she never tells them.', abilities: ['Dream Projection (shared subconscious manipulation)', 'Reality Blur (perception destabilization field)', 'Emotional Sync (linked emotional resonance)', 'Sleep Dominion (collective stasis induction)'], str: '14', dex: '18', con: '16', int: '20', wis: '22', cha: '20' }
