// ═══════════════════════════════════════════════════════════════════════════
// ALL CHARACTERS COMBINED
// ═══════════════════════════════════════════════════════════════════════════

export const ALL_CHARACTERS: Character[] = [
  ...GREATER_GODS,
  ...LESSER_GODS,
  ...DEMIGODS,
  ...HEROES,
  ...MONSTERS,
  ...ALL_KRYNN_CHARACTERS
]

// Get portrait path for a character
export function getPortraitPath(character: Character): string {
  return `/portraits/${character.category}/${character.id}.png?v=3`
}

// Get all unique pantheons
export function getAllPantheons(): string[] {
  const pantheons = new Set<string>()
  ALL_CHARACTERS.forEach(c => pantheons.add(c.pantheon))
  return Array.from(pantheons).sort()
}

// Filter characters by category
export function filterByCategory(category: string): Character[] {
  if (category === 'all') return ALL_CHARACTERS
  return ALL_CHARACTERS.filter(c => c.category === category)
}

// Filter characters by pantheon
export function filterByPantheon(pantheon: string): Character[] {
  if (pantheon === 'all') return ALL_CHARACTERS
  return ALL_CHARACTERS.filter(c => c.pantheon === pantheon)
}

// Search characters by name
export function searchCharacters(query: string): Character[] {
  const q = query.toLowerCase()
  return ALL_CHARACTERS.filter(c => 
    c.name.toLowerCase().includes(q) || 
    c.title.toLowerCase().includes(q) ||
    (c.domain && c.domain.toLowerCase().includes(q))
  )
}

// Get character by ID
export function getCharacterById(id: string): Character | undefined {
  return ALL_CHARACTERS.find(c => c.id === id)
}

// Get count of characters
export function getCharacterCounts(): { [key: string]: number } {
  return {
    all: ALL_CHARACTERS.length,
    'greater-gods': GREATER_GODS.length,
    'lesser-gods': LESSER_GODS.length,
    demigods: DEMIGODS.length,
    heroes: HEROES.length,
    monsters: MONSTERS.length,
    krynn: ALL_KRYNN_CHARACTERS.length
  }
}
